var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"종신 계약이라…….","JPN":"終身契約か……","ENG":"A lifetime contract, is it...","TWN":"終身雇傭嗎……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"여전히 괴상한 취미로군. 오래된 목소리.","JPN":"相変わらず変な真似をするのだな、古い声。","ENG":"You still have strange tastes, Old Voice.","TWN":"你的嗜好還是一樣古怪，古老的聲音。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 회사의 다른 녀석들에게도 이런 걸 제안하나?","JPN":"この会社の他の連中にもこういう提案をしているのか？","ENG":"Do you offer such things to the others in this company as well?","TWN":"你也會對公司的其他傢伙提出這種要求嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"애초에 의아할 지경이로군.","JPN":"そもそも、理解できない。","ENG":"I find the very notion rather absurd.","TWN":"從一開始就讓人感到不可思議。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈에게 이 따위 물러 터진 회사 놀이 같은 게 무슨 의미가 있지?","JPN":"こんな甘ったるい会社ごっこなど、貴様に何の意味がある？","ENG":"Tell me, what meaning does this foolish little company charade hold for you?","TWN":"對你來說，這種軟弱無力的公司遊戲究竟有什麼意義？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"다른 이들은 몰라도, 나는 네놈의 그림자를 잘 알고 있다.","JPN":"他の奴らは知らずとも、俺は貴様の裏の顔をよく知っている。","ENG":"Others may not, but I know your Shadow well.","TWN":"就算我不懂其他人，但我很了解你的影子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지금껏 수많은 세계를 반복해 온 네놈이라면, 인간의 마음을 홀리는 것쯤은 간단하겠지.","JPN":"今まで幾つもの世界を繰り返してきた貴様なら、人の心を惑わすことなど造作もないだろう。","ENG":"After repeating so many worlds, it must be simple for you to charm a human's heart.","TWN":"你這種反覆經歷過無數世界的傢伙，要蠱惑人心簡直輕而易舉吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"가족, 친구, 동료, 연인, 정의, 명예, 쾌락, 동경, 연대감, 책임감, 충성심…….","JPN":"家族、友、仲間、恋人、正義、名誉、快楽、憧れ、連帯感、責任感、忠誠心……","ENG":"Family, friends, comrades, lovers, justice, honor, pleasure, admiration, fellowship, responsibility, loyalty...","TWN":"家人、朋友、同伴、戀人、正義、名譽、快樂、憧憬、羈絆、責任感、忠誠……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"세계를 구한다는 대의로, 그들이 포기할 수 없는 온갖 것들을 인질삼아 희생을 강요했겠지.","JPN":"世界を救うという大義を掲げ、彼らが手放せない何かのために戦わざるを得ないよう、犠牲を押し付けたのだろう。","ENG":"In the name of saving the world, you took what they could never abandon and turned it into a hostage for sacrifice.","TWN":"你一定會以拯救世界的名義，把他們無法放棄的一切當成人質，逼迫他們犧牲吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그건 우리 세계의 기관이 추구하던 방식이었고.","JPN":"それは俺の世界の機関が追求していたやり方であり。","ENG":"That was the very method our world's Institution once pursued.","TWN":"那正是我們世界的機關曾經使用的方式。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"나아가, 기관의 뒤에서 예언을 남겼던 현자가 세계를 구하는 방식이었으니까.","JPN":"ひいては、機関の裏で予言を残した賢者が世界を救うやり方だったからな。","ENG":"It was also how the sage behind the Institution sought to save the world.","TWN":"更是那個在機關幕後留下預言的賢者，用來拯救世界的方法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"내 말이 틀렸나, 오래된 목소리여?","JPN":"違うか？　古い声。","ENG":"Am I wrong, Old Voice?","TWN":"我說錯了嗎？古老的聲音。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기관 녀석들은 네놈의 예언을 마치 대단한 전설이라도 되는 양, 받들고 추앙해 왔지.","JPN":"機関の連中は貴様の予言をまるで大層な伝説よろしく、崇め讃えてきた。","ENG":"The people of the Institution revered your prophecies as if they were some grand legend.","TWN":"那些機關的傢伙把你的預言當成偉大的傳說，非常崇拜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 그 전설의 말로에는 내가 있었다.","JPN":"だが、その伝説の末路には俺がいた。","ENG":"But at the end of that legend, there was me.","TWN":"可是在那個傳說的結局裡有我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 누구도, 그 무엇도 구할 수 없어서 절망할 수밖에 없었던 내가…….","JPN":"誰も、何も救えず絶望するしかなかった俺が……","ENG":"I, who could save no one and nothing, was left with nothing but despair...","TWN":"那個什麼人、什麼事都救不了，只能感到絕望的我……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"마지막의 마지막까지 충의를 다하지 못하고, 홀로 살아남아 버렸던 내가 있었다.","JPN":"最後の最後まで忠義を尽くせず、一人生き残ってしまった俺がいた。","ENG":"I, who failed my loyalty to the very end, survived alone.","TWN":"那個到最後的最後都未能盡忠，偏偏獨自活下來的我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그리고 어머니의 가호로써, 다시금 육체를 손에 넣은 지금에서야…….","JPN":"そしてお母さんの加護をもって再び肉体を手に入れた今……","ENG":"And only now, through Mother's blessing and my reclaimed body...","TWN":"而如今因為母親的庇佑，我才再次得到肉體……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"배반의 기사인 나는 비로소 네놈 앞에 설 수 있게 되었지.","JPN":"裏切りの騎士となった俺は、ようやく貴様の前に立つことができた。","ENG":"I, the Fallen Knight, can finally stand before you.","TWN":"我這個背叛的騎士終於能站在你面前。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그렇다면 대답해라, 오래된 목소리여.","JPN":"ならば答えろ、古い声よ。","ENG":"Then answer me, Old Voice.","TWN":"那麼回答我吧，古老的聲音。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈의 진정한 목적은 뭐지? 네놈은 어째서 무의미한 반복을 계속하고 있는 거냐!","JPN":"貴様の真の目的は何だ？　貴様はなぜ無意味なことを繰り返している！","ENG":"What is your true purpose? Why do you continue this meaningless repetition?!","TWN":"你真正的目的究竟是什麼？你為什麼要無止盡重複毫無意義的循環？"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 결말에는 틀림없이 절망이 기다리고 있다는 걸, 누구보다도 네놈이 가장 잘 알고 있을 터!","JPN":"その最後には必ず絶望が待っていることを、貴様は誰よりも分かっているはずだ！","ENG":"Of all beings, you must know best that every ending leads only to despair!","TWN":"你比任何人都清楚，最後在那裡等著你的只有絕望！"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"종신계약이라고? 웃기지 마라!","JPN":"終身契約だと？　ふざけるな！","ENG":"A lifetime contract? Don't make me laugh!","TWN":"終身雇傭？別開玩笑了！"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈은 그저 감언이설로 인간을 홀려, 또다시 함께한 이들을 절망의 구렁텅이로 밀어 넣고 말겠지!","JPN":"貴様は甘い言葉で人を惑わせ、共に歩んできた者たちを再び絶望の淵に突き落とすだろう！","ENG":"You'll only beguile more humans with sweet lies and drag those beside you back into the depths of despair!","TWN":"你只會用甜言蜜語迷惑人，然後再次把與你同行的人推入絕望的深淵！"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그럼에도… 그렇게까지 해서 네놈이 진정으로 원하는 게 뭐지……?","JPN":"それでも……そこまでして、貴様が真に望むものは何だ……？","ENG":"And yet... after all that, what is it that you truly desire...?","TWN":"即便如此……你這麼做到底想得到什麼……？"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"대답해라, 오래된 목소리여.","JPN":"答えろ、古い声よ。","ENG":"Answer me, Old Voice.","TWN":"回答我，古老的聲音。"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"답하지 않는다면, 여기서 네놈을 죽여 절망의 연쇄를 끊어내겠다.","JPN":"答えないなら、ここで貴様を殺し、絶望の連鎖を断ち切る。","ENG":"If you will not answer, I'll end you here and sever these chains of despair myself.","TWN":"如果你沉默，那我就在這裡親手殺了你，終結這條絕望的連鎖。"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈은……!","JPN":"貴様は……！","ENG":"You...!","TWN":"你……！"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"그때도, 그리고 지금도 내가 바라는 건, 세계 평화일 뿐이라네.","JPN":"あの時も、そして今も私が望むのは、ただ世界の平和のみだ。","ENG":"Then and now, all I wish for is world peace.","TWN":"我那時候跟現在追求的，只有世界和平而已。"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"세계 평화라고……?","JPN":"世界の平和だと……？","ENG":"World peace, you say?","TWN":"世界和平……？"},"stage":{"bg":"PRYDWEN_02","bgm":"UI_FIERCE_ESPR_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈……!","JPN":"貴様……！","ENG":"You...!","TWN":"你這傢伙……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"설마, 아직도 포기하지 않았다고……?","JPN":"まさか、まだ諦めていないというのか……？","ENG":"You still haven't given up...?","TWN":"你該不會到現在都還沒放棄吧……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그 수많은 세계의 멸망을 직면하고도… 그 수많은 이들의 최후를 마주하고도…….","JPN":"幾多の世界の滅亡を経験しても……幾多の者の最期を目にしても……","ENG":"After witnessing the collapse of countless worlds... and the final moments of so many lives...","TWN":"面對那麼多世界的滅亡……見證那麼多人的結局……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"지금 네놈은 뻔뻔스럽게도 포기하지 않았다고 답하는 건가?","JPN":"貴様は今、図々しくもまだ諦めていないなどとほざくのか？","ENG":"You shamelessly answer that you still haven't given up?","TWN":"你居然還能厚臉皮地說你沒有放棄？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"……후후, 미쳤군.","JPN":"……ふふ、狂っているな。","ENG":"...Haha. You're insane.","TWN":"……呵呵，原來你瘋了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"오래된 목소리, 네놈도 잘 알고 있겠지? 넌 제정신이 아니야.","JPN":"古い声、貴様もよく分かっているだろう？　貴様は正気ではない。","ENG":"Old Voice, you know it yourself. You've lost your mind.","TWN":"古老的聲音，你也很清楚吧？你不正常。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈도 나와 똑같이 벌써 오래전에 미쳐버린 거다.","JPN":"貴様も俺と同じく、とっくに狂ってしまっていたのだ。","ENG":"You went mad long ago, just like me.","TWN":"你也跟我一樣，從很久以前就瘋了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"하지만 적어도 흥미는 생겼군.","JPN":"だが、少なくとも興味は湧いた。","ENG":"Still, you've caught my interest.","TWN":"不過至少讓我產生興趣了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그러니 한동안은 네놈의 회사 놀이에 어울려주도록 하겠다.","JPN":"しばらくの間、貴様の会社ごっこに付き合ってやってもいいぞ。","ENG":"So for a while, I’ll go along with your company charade.","TWN":"那我就暫時陪你玩這個公司遊戲吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};